INSERT INTO "controls" VALUES('A.5.1','A.5.1','Políticas para segurança de informação','Definir, aprovar, publicar, comunicar e rever periodicamente políticas de segurança de informação.','Organizacional','ISO 27001:2022 A.5.1 · NIS2 Art.21(2)(a)','partial','needs_improvement','DTI - ISO','','Política existe mas não revista há mais de 12 meses; falta cascata para subsidiárias.','2026-05-18 12:49:46','2026-05-18 12:49:46');
INSERT INTO "controls" VALUES('A.5.2','A.5.2','Papéis e responsabilidades de segurança de informação','Definir e atribuir papéis e responsabilidades de segurança de informação de acordo com as necessidades da organização.','Organizacional','ISO 27001:2022 A.5.2','partial','needs_improvement','DTI - ISO','','CISO existe; falta formalização de papéis nas subsidiárias e separação de funções.','2026-05-18 12:49:46','2026-05-18 12:49:46');
INSERT INTO "controls" VALUES('A.5.9','A.5.9','Inventário de informação e ativos associados','Manter um inventário atualizado de informação e outros ativos associados, incluindo proprietários.','Organizacional','ISO 27001:2022 A.5.9 · NIS2 Art.21(2)(i)','implemented','needs_improvement','DTI - Arquitetura','','Inventário disponível na plataforma; rever periodicidade de atualização.','2026-05-18 12:49:46','2026-05-18 12:49:46');
INSERT INTO "controls" VALUES('A.5.10','A.5.10','Uso aceitável de informação e outros ativos','Identificar, documentar e implementar regras para o uso aceitável de informação e ativos.','Organizacional','ISO 27001:2022 A.5.10','not_implemented','ineffective','DTI - ISO','R022','Sem política formal sobre uso de IA generativa (Shadow AI); colaboradores usam ChatGPT sem regras.','2026-05-18 12:49:46','2026-05-18 12:49:46');
INSERT INTO "controls" VALUES('A.5.12','A.5.12','Classificação de informação','Classificar a informação de acordo com requisitos de confidencialidade, integridade, disponibilidade e legais.','Organizacional','ISO 27001:2022 A.5.12','not_implemented','ineffective','DPO + DTI - ISO','R025','Sem esquema de classificação aplicado; impossível aplicar controlos diferenciados.','2026-05-18 12:49:46','2026-05-18 12:49:46');
INSERT INTO "controls" VALUES('A.5.15','A.5.15','Controlo de acessos','Estabelecer e implementar regras para controlo de acessos físicos e lógicos com base em requisitos de negócio e segurança.','Organizacional','ISO 27001:2022 A.5.15 · NIS2 Art.21(2)(i)','partial','needs_improvement','DTI - Operações','R004','Existe controlo de acessos no AD; falta política formal e revisões periódicas.','2026-05-18 12:49:46','2026-05-18 12:49:46');
INSERT INTO "controls" VALUES('A.5.16','A.5.16','Gestão de identidades','Gerir o ciclo de vida completo das identidades.','Organizacional','ISO 27001:2022 A.5.16','partial','needs_improvement','DTI - Operações','R018','Identidades geridas no AD; ciclo de vida com processos manuais.','2026-05-18 12:49:46','2026-05-18 12:49:46');
INSERT INTO "controls" VALUES('A.5.17','A.5.17','Informação de autenticação','Gerir alocação e gestão de informação de autenticação (passwords, chaves, tokens).','Organizacional','ISO 27001:2022 A.5.17 · NIS2 Art.21(2)(j)','partial','needs_improvement','DTI - Operações','R026','Política de passwords existe; MFA não estendido a todas as contas privilegiadas.','2026-05-18 12:49:46','2026-05-18 12:49:46');
INSERT INTO "controls" VALUES('A.5.18','A.5.18','Direitos de acesso','Provisionar, rever, modificar e remover direitos de acesso de acordo com a política da organização.','Organizacional','ISO 27001:2022 A.5.18 · NIS2 Art.21(2)(i)','partial','needs_improvement','DTI - Operações','R004,R018','Onboarding/offboarding manuais; sem revisões periódicas de acessos (recertificação).','2026-05-18 12:49:46','2026-05-18 12:49:46');
INSERT INTO "controls" VALUES('A.5.19','A.5.19','Segurança da informação em relações com fornecedores','Definir processos e procedimentos para gerir riscos de segurança associados ao uso de produtos e serviços de fornecedores.','Organizacional','ISO 27001:2022 A.5.19 · NIS2 Art.21(2)(d)','partial','needs_improvement','DTI + Compras','R007,R033,R024','Avaliações ad-hoc; sem processo TPRM estruturado para todos os fornecedores críticos.','2026-05-18 12:49:46','2026-05-18 12:49:46');
INSERT INTO "controls" VALUES('A.5.24','A.5.24','Planeamento e preparação para gestão de incidentes','Planear e preparar a gestão de incidentes de segurança definindo processos, papéis e responsabilidades.','Organizacional','ISO 27001:2022 A.5.24 · NIS2 Art.21(2)(b)','not_implemented','ineffective','DTI - ISO','R036','Sem plano formal de resposta a incidentes documentado e testado.','2026-05-18 12:49:46','2026-05-18 12:49:46');
INSERT INTO "controls" VALUES('A.5.25','A.5.25','Avaliação e decisão sobre eventos de segurança','Avaliar eventos de segurança e decidir se constituem incidentes.','Organizacional','ISO 27001:2022 A.5.25 · NIS2 Art.21(2)(b)','not_implemented','ineffective','DTI - ISO','R035','Sem processo formal para triagem; cumprimento do aviso 72h CNPD em risco.','2026-05-18 12:49:46','2026-05-18 12:49:46');
INSERT INTO "controls" VALUES('A.5.26','A.5.26','Resposta a incidentes de segurança','Responder a incidentes de segurança de acordo com procedimentos documentados.','Organizacional','ISO 27001:2022 A.5.26 · NIS2 Art.21(2)(b)','not_implemented','ineffective','DTI - ISO','R036,R037','Sem playbooks; sem retainer com empresa especializada em resposta a incidentes.','2026-05-18 12:49:46','2026-05-18 12:49:46');
INSERT INTO "controls" VALUES('A.5.29','A.5.29','Segurança da informação durante disrupção','Planear como manter segurança da informação a um nível apropriado durante disrupção.','Organizacional','ISO 27001:2022 A.5.29 · NIS2 Art.21(2)(c)','not_implemented','ineffective','DTI - ISO','R012','Sem BCP formal; expectativas indefinidas durante crise.','2026-05-18 12:49:46','2026-05-18 12:49:46');
INSERT INTO "controls" VALUES('A.5.30','A.5.30','Prontidão TIC para continuidade de negócio','Planear, implementar, manter e testar prontidão TIC com base nos objectivos de continuidade.','Organizacional','ISO 27001:2022 A.5.30 · NIS2 Art.21(2)(c)','not_implemented','ineffective','DTI - Arquitetura','R012','Sem DR formal; RTO/RPO não definidos para sistemas críticos.','2026-05-18 12:49:46','2026-05-18 12:49:46');
INSERT INTO "controls" VALUES('A.5.31','A.5.31','Requisitos legais, estatutários, regulamentares e contratuais','Identificar, documentar e manter atualizados todos os requisitos legais e regulamentares aplicáveis.','Organizacional','ISO 27001:2022 A.5.31','partial','needs_improvement','DPO + Jurídico','R008,R009','RGPD parcialmente conforme; NIS2 em transição; sem inventário centralizado de obrigações.','2026-05-18 12:49:46','2026-05-18 12:49:46');
INSERT INTO "controls" VALUES('A.5.34','A.5.34','Privacidade e proteção de informação pessoal (PII)','Identificar e cumprir requisitos relativos à preservação de privacidade e proteção de PII.','Organizacional','ISO 27001:2022 A.5.34 · RGPD','partial','needs_improvement','DPO','R008,R028,R032,R033,R034','RoPA incompleto; DPIAs em falta; retenção excessiva; transferências internacionais sem salvaguardas formais.','2026-05-18 12:49:46','2026-05-18 12:49:46');
INSERT INTO "controls" VALUES('A.5.37','A.5.37','Procedimentos operacionais documentados','Documentar procedimentos operacionais para atividades de segurança e disponibilizá-los a quem precisa.','Organizacional','ISO 27001:2022 A.5.37','partial','needs_improvement','DTI - Operações','R027','Procedimentos críticos não documentados; conhecimento concentrado em pessoas-chave.','2026-05-18 12:49:46','2026-05-18 12:49:46');
INSERT INTO "controls" VALUES('A.6.3','A.6.3','Consciencialização, educação e formação em segurança da informação','Garantir consciencialização, educação e formação adequada e atualizações periódicas para todos os colaboradores.','Pessoas','ISO 27001:2022 A.6.3 · NIS2 Art.21(2)(g)','not_implemented','ineffective','DTI - ISO + RH','R006','Sem programa formal de awareness; sem simulações de phishing periódicas.','2026-05-18 12:49:46','2026-05-18 12:49:46');
INSERT INTO "controls" VALUES('A.6.8','A.6.8','Reporte de eventos de segurança da informação','Disponibilizar mecanismos para os colaboradores reportarem eventos de segurança observados ou suspeitos.','Pessoas','ISO 27001:2022 A.6.8 · NIS2 Art.21(2)(b)','partial','needs_improvement','DTI - ISO','','Canal de reporte existe (email) mas pouco divulgado; sem SLA de resposta.','2026-05-18 12:49:46','2026-05-18 12:49:46');
INSERT INTO "controls" VALUES('A.7.1','A.7.1','Perímetros de segurança física','Definir e usar perímetros de segurança para proteger áreas com informação e ativos críticos.','Físico','ISO 27001:2022 A.7.1','implemented','effective','DTI + Facilities','','Perímetros estabelecidos; revisão anual recomendada.','2026-05-18 12:49:46','2026-05-18 12:49:46');
INSERT INTO "controls" VALUES('A.7.2','A.7.2','Entradas físicas','Proteger áreas seguras por controlos de entrada e pontos de acesso adequados.','Físico','ISO 27001:2022 A.7.2','implemented','needs_improvement','DTI + Facilities','R016','Cartões e fechaduras eletrónicas; rever processos de visitantes e revogação de acessos.','2026-05-18 12:49:46','2026-05-18 12:49:46');
INSERT INTO "controls" VALUES('A.7.5','A.7.5','Proteção contra ameaças físicas e ambientais','Conceber e implementar proteção contra ameaças físicas e ambientais (incêndio, inundação, etc.).','Físico','ISO 27001:2022 A.7.5','implemented','needs_improvement','DTI + Facilities','R015','Datacenter com detecção de incêndio e UPS; falta teste regular dos dispositivos.','2026-05-18 12:49:46','2026-05-18 12:49:46');
INSERT INTO "controls" VALUES('A.8.2','A.8.2','Direitos de acesso privilegiado','Restringir e gerir a alocação de direitos de acesso privilegiados.','Tecnológico','ISO 27001:2022 A.8.2 · NIS2 Art.21(2)(i)','partial','needs_improvement','DTI - Operações','R026','Contas administrativas identificadas; sem PAM (Privileged Access Management).','2026-05-18 12:49:46','2026-05-18 12:49:46');
INSERT INTO "controls" VALUES('A.8.7','A.8.7','Proteção contra malware','Implementar proteção contra malware suportada por consciencialização adequada dos utilizadores.','Tecnológico','ISO 27001:2022 A.8.7 · NIS2 Art.21(2)(h)','partial','needs_improvement','DTI - Operações','R003','Antivírus em todos os endpoints; sem EDR moderno com capacidades de detecção comportamental.','2026-05-18 12:49:46','2026-05-18 12:49:46');
INSERT INTO "controls" VALUES('A.8.8','A.8.8','Gestão de vulnerabilidades técnicas','Obter informação sobre vulnerabilidades técnicas, avaliar exposição e tomar medidas apropriadas.','Tecnológico','ISO 27001:2022 A.8.8 · NIS2 Art.21(2)(e)','partial','needs_improvement','DTI - Operações','R011','Scans pontuais; sem processo formal de patch management nem SLA por criticidade.','2026-05-18 12:49:46','2026-05-18 12:49:46');
INSERT INTO "controls" VALUES('A.8.10','A.8.10','Eliminação de informação','Eliminar informação armazenada em sistemas, dispositivos ou outros suportes quando já não é necessária.','Tecnológico','ISO 27001:2022 A.8.10 · RGPD Art.5(e)','not_implemented','ineffective','DPO + DTI - Operações','R028','Sem política de retenção formal aplicada; dados pessoais guardados indefinidamente.','2026-05-18 12:49:46','2026-05-18 12:49:46');
INSERT INTO "controls" VALUES('A.8.13','A.8.13','Cópias de segurança de informação','Manter cópias de segurança da informação, software e sistemas e testá-las periodicamente.','Tecnológico','ISO 27001:2022 A.8.13 · NIS2 Art.21(2)(c)','partial','untested','DTI - Operações','R005','Cópias de segurança automatizadas; restauros não testados regularmente.','2026-05-18 12:49:46','2026-05-18 12:49:46');
INSERT INTO "controls" VALUES('A.8.14','A.8.14','Redundância de instalações de processamento de informação','Implementar instalações de processamento com redundância suficiente para cumprir requisitos de disponibilidade.','Tecnológico','ISO 27001:2022 A.8.14 · NIS2 Art.21(2)(c)','partial','needs_improvement','DTI - Arquitetura','R002,R020','Algum nível de redundância em servidores; ponto único de falha em telecomunicações.','2026-05-18 12:49:46','2026-05-18 12:49:46');
INSERT INTO "controls" VALUES('A.8.15','A.8.15','Registo (logging)','Produzir, armazenar, proteger e analisar registos de atividades, exceções e eventos de segurança.','Tecnológico','ISO 27001:2022 A.8.15 · NIS2 Art.21(2)(f)','partial','needs_improvement','DTI - Operações','R029','Logs gerados localmente; sem centralização nem retenção mínima garantida.','2026-05-18 12:49:46','2026-05-18 12:49:46');
INSERT INTO "controls" VALUES('A.8.16','A.8.16','Monitorização de atividades','Monitorizar redes, sistemas e aplicações para detetar comportamentos anómalos e potenciais incidentes.','Tecnológico','ISO 27001:2022 A.8.16 · NIS2 Art.21(2)(f)','not_implemented','ineffective','DTI - ISO','R017','Sem SIEM/MDR; sem detecção centralizada de eventos de segurança.','2026-05-18 12:49:46','2026-05-18 12:49:46');
INSERT INTO "controls" VALUES('A.8.24','A.8.24','Uso de criptografia','Definir e implementar regras para uso eficaz de criptografia, incluindo gestão de chaves.','Tecnológico','ISO 27001:2022 A.8.24 · NIS2 Art.21(2)(h)','partial','needs_improvement','DTI - Arquitetura','R030','Cifragem aplicada em comunicações e BD principais; gestão de chaves não documentada.','2026-05-18 12:49:46','2026-05-18 12:49:46');
INSERT INTO "controls" VALUES('A.8.25','A.8.25','Ciclo de vida de desenvolvimento seguro','Estabelecer e aplicar regras para o desenvolvimento seguro de software e sistemas.','Tecnológico','ISO 27001:2022 A.8.25 · NIS2 Art.21(2)(e)','not_implemented','ineffective','DTI - Desenvolvimento','R031','Sem SDLC formal; sem revisões de código de segurança.','2026-05-18 12:49:46','2026-05-18 12:49:46');
INSERT INTO "controls" VALUES('A.8.28','A.8.28','Codificação segura','Aplicar princípios de codificação segura ao desenvolvimento de software.','Tecnológico','ISO 27001:2022 A.8.28 · NIS2 Art.21(2)(e)','not_implemented','ineffective','DTI - Desenvolvimento','R031','Sem standards de codificação segura; sem SAST/DAST integrados no pipeline.','2026-05-18 12:49:46','2026-05-18 12:49:46');
INSERT INTO "controls" VALUES('NIS2.20','NIS2.20','Governança — Responsabilidade do órgão de administração','O órgão de administração das entidades essenciais e importantes aprova as medidas de gestão de risco de cibersegurança, supervisiona a sua implementação e é responsabilizável por incumprimentos. Os membros são obrigados a frequentar ações de formação periódicas para identificarem e avaliarem práticas de gestão de risco de cibersegurança.','Regulamentar','NIS2 Art.20','partial','needs_improvement','Direção / ISO','R009','Plano A009 (aprovação formal da política pela Direção) em curso. Falta plano de formação obrigatória para Conselho de Administração.','2026-05-19 10:27:55','2026-05-20 14:15:59');
INSERT INTO "controls" VALUES('NIS2.21.2.a','NIS2.21.2.a','Políticas de análise de risco e segurança dos sistemas de informação','Estabelecer políticas formais para análise de risco e para a segurança dos sistemas de informação, documentadas, aprovadas pela direção e revistas periodicamente. Aplicar abordagem baseada em todos os riscos (cyber, físico, ambiental, humano).','Regulamentar','NIS2 Art.21(2)(a)','partial','needs_improvement','ISO','R009','Processo de gestão de risco está operacional (esta plataforma). Política formal NIS2-aligned ainda não aprovada pela Direção.','2026-05-19 10:27:55','2026-05-19 10:27:55');
INSERT INTO "controls" VALUES('NIS2.21.2.b','NIS2.21.2.b','Tratamento de incidentes','Procedimentos para deteção, análise, contenção, erradicação, recuperação e lições aprendidas de incidentes. Classificação por severidade, cadeia de escalonamento documentada, equipa de resposta (CSIRT/SOC interno ou externo) com competências definidas.','Regulamentar','NIS2 Art.21(2)(b)','partial','needs_improvement','ISO / DTI - Segurança','R035,R009','Equipa de resposta informal existe. Falta runbook documentado, classificação de incidentes e teste do processo de escalonamento.','2026-05-19 10:27:55','2026-05-19 10:27:55');
INSERT INTO "controls" VALUES('NIS2.21.2.c','NIS2.21.2.c','Continuidade das atividades, backup e gestão de crises','Inclui: gestão de cópias de segurança (3-2-1), recuperação após desastre (DR) com RTO/RPO definidos por sistema crítico, plano de continuidade de negócio (BCP) testado periodicamente, e gestão de crises com porta-vozes e comunicação interna/externa.','Regulamentar','NIS2 Art.21(2)(c)','not_implemented','ineffective','Direção / DTI','R012,R005,R024','Risco R012 — ausência de BCP formal. Backups existem (Commvault) mas crisis management não está formalizado.','2026-05-19 10:27:55','2026-05-19 10:27:55');
INSERT INTO "controls" VALUES('NIS2.21.2.d','NIS2.21.2.d','Segurança da cadeia de fornecimento','Avaliação e gestão dos riscos decorrentes das relações com fornecedores diretos e prestadores de serviços. Inclui due diligence pré-contratual, cláusulas de segurança obrigatórias, direito de auditoria, requisitos de notificação de incidentes pelo fornecedor.','Regulamentar','NIS2 Art.21(2)(d)','planned','untested','Compras / ISO','R007,R024,R033','Plano A007 (TPRM formal) ainda não iniciado. Sem questionários de avaliação enviados a fornecedores críticos.','2026-05-19 10:27:55','2026-05-19 14:39:30');
INSERT INTO "controls" VALUES('NIS2.21.2.e','NIS2.21.2.e','Segurança na aquisição, desenvolvimento e manutenção de sistemas','Inclui gestão de vulnerabilidades técnicas, divulgação coordenada (CVD), revisão de código segura, requisitos de segurança no SDLC, e gestão de patches em prazos definidos por criticidade.','Regulamentar','NIS2 Art.21(2)(e)','partial','needs_improvement','DTI - Infra / DTI - Dev','R011,R003','Patching crítico ainda em 30 dias (plano A011 para reduzir a 7). Sem programa formal de vulnerability disclosure.','2026-05-19 10:27:55','2026-05-19 10:27:55');
INSERT INTO "controls" VALUES('NIS2.21.2.f','NIS2.21.2.f','Políticas e procedimentos de avaliação da eficácia das medidas','Mecanismos para avaliar periodicamente a eficácia das medidas implementadas: auditorias internas, testes de intrusão, exercícios de simulação (red/purple team), métricas KPI/KRI de cibersegurança e reporting periódico ao órgão de administração.','Regulamentar','NIS2 Art.21(2)(f)','not_implemented','untested','ISO / Auditoria Interna','R009','Sem auditorias internas planeadas, sem pentest periódico, sem framework de KPIs de cibersegurança.','2026-05-19 10:27:55','2026-05-19 10:27:55');
INSERT INTO "controls" VALUES('NIS2.21.2.g','NIS2.21.2.g','Higiene cibernética básica e formação em cibersegurança','Programas de formação obrigatória para todos os colaboradores e formação especializada para perfis técnicos. Cobre phishing, password hygiene, classificação da informação, procedimentos de reporte e práticas seguras em mobilidade/teletrabalho.','Regulamentar','NIS2 Art.21(2)(g)','partial','needs_improvement','ISO / RH','R006','Plano A006 (simulações trimestrais de phishing) em execução. Falta currículo formal e completion tracking.','2026-05-19 10:27:55','2026-05-19 10:27:55');
INSERT INTO "controls" VALUES('NIS2.21.2.h','NIS2.21.2.h','Políticas e procedimentos sobre criptografia e cifragem','Política formal de criptografia: algoritmos aprovados (ex: AES-256, RSA-2048+), gestão de chaves (KMS), cifragem de dados em repouso (databases, backups, endpoints) e em trânsito (TLS 1.2+). Aplicação especial para dados pessoais.','Regulamentar','NIS2 Art.21(2)(h)','partial','needs_improvement','DTI - Segurança','R033,R008','TLS/HTTPS em uso. Falta política formal, inventário de uso de cifragem em databases e gestão centralizada de chaves.','2026-05-19 10:27:55','2026-05-19 10:27:55');
INSERT INTO "controls" VALUES('NIS2.21.2.i','NIS2.21.2.i','Segurança de recursos humanos, controlo de acessos e gestão de ativos','Política de acesso baseada em least-privilege, revisão periódica de acessos, gestão do ciclo joiners-movers-leavers, due diligence em onboarding, inventário atualizado de ativos com classificação de criticidade.','Regulamentar','NIS2 Art.21(2)(i)','partial','needs_improvement','DTI - Segurança / RH','R004,R009','Plano A004 (revisão trimestral de acessos) em curso. Inventário de ativos parcial.','2026-05-19 10:27:55','2026-05-19 10:27:55');
INSERT INTO "controls" VALUES('NIS2.21.2.j','NIS2.21.2.j','Autenticação multifator (MFA) e comunicações seguras','MFA obrigatório para acessos privilegiados e a sistemas críticos. Comunicações de voz, vídeo e texto cifradas dentro da entidade. Sistemas seguros de comunicação de emergência (out-of-band) para gestão de crises quando os canais habituais estão comprometidos.','Regulamentar','NIS2 Art.21(2)(j)','partial','needs_improvement','DTI - Segurança','R003,R004','Plano A001 (expansão MFA a 100% do portfólio) em curso. Comunicações de emergência out-of-band não definidas.','2026-05-19 10:27:55','2026-05-19 10:27:55');
INSERT INTO "controls" VALUES('NIS2.21.3','NIS2.21.3','Considerações específicas sobre cada fornecedor direto','Ao avaliar fornecedores, ter em conta as vulnerabilidades específicas de cada fornecedor direto, a qualidade global dos produtos e as práticas de cibersegurança dos fornecedores (incluindo procedimentos de desenvolvimento seguro), e os resultados de avaliações coordenadas a nível da UE (Art. 22) sobre cadeias de abastecimento críticas.','Regulamentar','NIS2 Art.21(3)','not_implemented','untested','Compras / ISO','R007,R033','Sem matriz de avaliação por fornecedor. Aguardar publicação das avaliações coordenadas UE (DNS, cloud, MSP).','2026-05-19 10:27:55','2026-05-19 10:27:55');
INSERT INTO "controls" VALUES('NIS2.21.4','NIS2.21.4','Medidas corretivas em caso de não conformidade','Quando a entidade conclui que não cumpre as medidas do Art. 21(2), deve tomar todas as medidas corretivas necessárias, adequadas e proporcionadas, sem demora injustificada. Implica processo formal de gap assessment, planos de remediação com prazos, e tracking de progresso.','Regulamentar','NIS2 Art.21(4)','partial','needs_improvement','ISO','R009','Esta plataforma (planos de ação) suporta gap remediation. Falta gap assessment formal contra Art. 21(2).','2026-05-19 10:27:55','2026-05-19 10:27:55');
INSERT INTO "controls" VALUES('NIS2.23.4.a','NIS2.23.4.a','Alerta precoce — 24 horas','Comunicação inicial ao CSIRT competente (em PT: CNCS) no prazo de 24h após tomada de conhecimento de incidente significativo. Deve indicar se há suspeita de ato ilícito/malicioso e se pode ter impacto transfronteiriço.','Regulamentar','NIS2 Art.23(4)(a)','not_implemented','ineffective','ISO','R035','Sem procedimento definido. Sem canal estabelecido com o CNCS (CSIRT nacional PT).','2026-05-19 10:27:55','2026-05-19 14:40:49');
INSERT INTO "controls" VALUES('NIS2.23.4.b','NIS2.23.4.b','Notificação de incidente — 72 horas','Notificação completa ao CSIRT em 72h após tomada de conhecimento de incidente significativo. Atualiza o alerta precoce com avaliação inicial do incidente, severidade, impacto e indicadores de exposição a riscos disponíveis (IoCs).','Regulamentar','NIS2 Art.23(4)(b)','not_implemented','ineffective','ISO','R035','Risco R035 explicitamente identifica esta lacuna. Sem template, sem owner, sem cadeia de escalonamento.','2026-05-19 10:27:55','2026-05-19 10:27:55');
INSERT INTO "controls" VALUES('NIS2.23.4.d','NIS2.23.4.d','Relatório final — 1 mês','Relatório final ao CSIRT em 1 mês após a notificação de 72h, contendo: descrição pormenorizada do incidente e impacto, tipo de ameaça/causa primária, medidas de mitigação aplicadas, impacto transfronteiriço (se aplicável). Se incidente em curso à data, apresentar relatório intercalar.','Regulamentar','NIS2 Art.23(4)(d)','not_implemented','ineffective','ISO','R035','Sem template de post-incident review formalizado.','2026-05-19 10:27:55','2026-05-19 10:27:55');
INSERT INTO "controls" VALUES('NIS2.23.dest','NIS2.23.dest','Comunicação a destinatários dos serviços afetados','Quando um incidente significativo possa afetar negativamente a prestação de serviços, comunicar sem demora indevida aos destinatários (clientes/utilizadores). Quando há ciberameaça significativa que os pode afetar, comunicar as medidas/soluções que podem adotar.','Regulamentar','NIS2 Art.23(1)/(2)','not_implemented','ineffective','ISO / Comunicação','R035','Sem template de comunicação externa de incidentes. Sem matriz de decisão sobre quando comunicar.','2026-05-19 10:27:55','2026-05-19 10:27:55');
INSERT INTO "controls" VALUES('NIS2.24','NIS2.24','Utilização de sistemas europeus de certificação de cibersegurança','Quando aplicável, utilizar produtos, serviços e processos TIC certificados ao abrigo de esquemas europeus de certificação (EUCC para produtos, EUCS para serviços cloud) para demonstrar conformidade. A Comissão pode tornar obrigatório em setores específicos por atos delegados.','Regulamentar','NIS2 Art.24','not_applicable','untested','DTI / Compras','','Esquemas EUCC/EUCS ainda em adoção pelos fornecedores. Reavaliar em 2027.','2026-05-19 10:27:55','2026-05-19 10:27:55');
INSERT INTO "controls" VALUES('NIS2.27','NIS2.27','Registo de entidades junto da autoridade nacional','Aplicável a prestadores de serviços de DNS, registos TLD, prestadores de serviços de nuvem, centros de dados, CDN, MSP, MSSP, marketplaces online, motores de pesquisa e plataformas de redes sociais. Devem registar-se até 17/01/2025 junto da autoridade nacional, fornecendo nome, setor, contactos, endereços IP e EMs onde prestam serviços.','Regulamentar','NIS2 Art.27','not_applicable','untested','ISO','','Não aplicável — a organização não opera nenhum dos serviços digitais listados no Art. 27(1). O estatuto NIS2 é atribuído pela autoridade competente via Anexo I/II.','2026-05-19 10:27:55','2026-05-19 10:27:55');
INSERT INTO "controls" VALUES('NIS2.29','NIS2.29','Acordos de partilha de informações sobre cibersegurança','Participação voluntária em acordos formais de partilha de informação cyber (ISACs, comunidades setoriais, plataformas TIC dedicadas) para troca de IoCs, TTPs, tendências de ameaças e boas práticas. Notificar a autoridade competente da adesão e saída.','Regulamentar','NIS2 Art.29','not_implemented','untested','ISO','','Sem participação em ISACs ou comunidades setoriais. Avaliar adesão ao H-ISAC (saúde) e CNCS Community.','2026-05-19 10:27:55','2026-05-19 10:27:55');
INSERT INTO "controls" VALUES('NIS2.30','NIS2.30','Notificação voluntária de quase-incidentes e ciberameaças','Para além das notificações obrigatórias (Art. 23), as entidades podem notificar voluntariamente ao CSIRT: quase-incidentes (near-misses), ciberameaças detetadas e incidentes não-significativos. Beneficia da partilha agregada de tendências pela ENISA.','Regulamentar','NIS2 Art.30','not_implemented','untested','ISO','','Sem processo definido para canalizar near-misses ao CNCS.','2026-05-19 10:27:55','2026-05-19 10:27:55');
INSERT INTO "controls" VALUES('NIS2.32','NIS2.32','Cooperação com medidas de supervisão e execução','Cooperação plena com a autoridade nacional competente em medidas de supervisão: inspeções in loco e fora do local, auditorias de segurança (regulares e ad-hoc), análises de segurança (scans), pedidos de informação, acesso a dados, documentos e medidas implementadas. Aplicável a entidades essenciais.','Regulamentar','NIS2 Art.32','not_implemented','untested','ISO / Direção','','Sem auditorias da autoridade competente realizadas até à data. Capacidade de resposta a pedidos formais por testar.','2026-05-19 10:27:55','2026-05-19 10:27:55');
INSERT INTO "controls" VALUES('NIS2.35','NIS2.35','Coordenação RGPD-NIS2 em incidentes com dados pessoais','Quando um incidente significativo NIS2 implica violação de dados pessoais, articular as notificações: 24h CSIRT (NIS2) + 72h CNPD (RGPD). Procedimento conjunto único, evitando duplicação. As autoridades NIS2 e RGPD cooperam entre si.','Regulamentar','NIS2 Art.35 + RGPD Art.33','partial','needs_improvement','ISO / DPO','R035,R008,R033','DPO designado. Procedimento conjunto NIS2+RGPD para incidentes mistos ainda não documentado.','2026-05-19 10:27:55','2026-05-19 10:27:55');
INSERT INTO "controls" VALUES('A.5.3','A.5.3','Segregação de funções','Funções conflituantes e áreas de responsabilidade conflituantes devem ser segregadas.','Organizacional','ISO 27001:2022 A.5.3','partial','needs_improvement','ISO / RH','','','2026-05-20 10:26:04','2026-05-20 10:26:04');
INSERT INTO "controls" VALUES('A.5.4','A.5.4','Responsabilidades da direção','A direção deve exigir a todo o pessoal que aplique segurança de informação de acordo com a política, políticas específicas e procedimentos estabelecidos pela organização.','Organizacional','ISO 27001:2022 A.5.4','implemented','effective','Direção','','','2026-05-20 10:26:04','2026-05-20 10:26:04');
INSERT INTO "controls" VALUES('A.5.5','A.5.5','Contacto com autoridades','A organização deve estabelecer e manter contacto com as autoridades relevantes.','Organizacional','ISO 27001:2022 A.5.5','partial','needs_improvement','ISO','','','2026-05-20 10:26:04','2026-05-20 10:26:04');
INSERT INTO "controls" VALUES('A.5.6','A.5.6','Contacto com grupos de interesse especial','A organização deve estabelecer e manter contacto com grupos de interesse especial ou outros fóruns especializados em segurança e associações profissionais.','Organizacional','ISO 27001:2022 A.5.6','planned','untested','ISO','','','2026-05-20 10:26:04','2026-05-20 10:26:04');
INSERT INTO "controls" VALUES('A.5.7','A.5.7','Inteligência sobre ameaças','Informação relativa a ameaças à segurança de informação deve ser recolhida e analisada para produzir inteligência sobre ameaças (Threat Intelligence).','Organizacional','ISO 27001:2022 A.5.7','not_implemented','untested','DTI - Segurança','','','2026-05-20 10:26:04','2026-05-20 10:26:04');
INSERT INTO "controls" VALUES('A.5.8','A.5.8','Segurança de informação na gestão de projetos','A segurança de informação deve ser integrada na gestão de projetos.','Organizacional','ISO 27001:2022 A.5.8','partial','needs_improvement','PMO / ISO','','','2026-05-20 10:26:04','2026-05-20 10:26:04');
INSERT INTO "controls" VALUES('A.5.11','A.5.11','Devolução de ativos','Pessoal e outras partes interessadas, conforme aplicável, devem devolver todos os ativos da organização na sua posse após mudança ou cessação do contrato.','Organizacional','ISO 27001:2022 A.5.11','implemented','effective','RH','','','2026-05-20 10:26:04','2026-05-20 10:26:04');
INSERT INTO "controls" VALUES('A.5.13','A.5.13','Rotulagem de informação','Um conjunto adequado de procedimentos para rotulagem de informação deve ser desenvolvido e implementado de acordo com o esquema de classificação adotado.','Organizacional','ISO 27001:2022 A.5.13','not_implemented','untested','ISO','','','2026-05-20 10:26:04','2026-05-20 10:26:04');
INSERT INTO "controls" VALUES('A.5.14','A.5.14','Transferência de informação','Regras, procedimentos ou acordos de transferência de informação devem estar em vigor para todos os tipos de transferência dentro da organização e entre a organização e outras partes.','Organizacional','ISO 27001:2022 A.5.14','partial','needs_improvement','ISO','','','2026-05-20 10:26:04','2026-05-20 10:26:04');
INSERT INTO "controls" VALUES('A.5.20','A.5.20','Tratamento de segurança de informação em acordos com fornecedores','Requisitos relevantes de segurança de informação devem ser estabelecidos e acordados com cada fornecedor, com base no tipo de relação de fornecimento.','Organizacional','ISO 27001:2022 A.5.20','planned','untested','Compras / ISO','','','2026-05-20 10:26:04','2026-05-20 10:26:04');
INSERT INTO "controls" VALUES('A.5.21','A.5.21','Gestão de segurança de informação na cadeia de fornecimento TIC','Processos e procedimentos devem ser definidos e implementados para gerir os riscos de segurança de informação associados à cadeia de abastecimento de produtos e serviços TIC.','Organizacional','ISO 27001:2022 A.5.21','not_implemented','untested','Compras / ISO','','','2026-05-20 10:26:04','2026-05-20 10:26:04');
INSERT INTO "controls" VALUES('A.5.22','A.5.22','Monitorização, revisão e gestão de mudança de serviços de fornecedores','A organização deve monitorizar, rever, avaliar e gerir a mudança nas práticas de segurança de informação dos fornecedores e na entrega dos serviços.','Organizacional','ISO 27001:2022 A.5.22','not_implemented','untested','Compras / ISO','','','2026-05-20 10:26:04','2026-05-20 10:26:04');
INSERT INTO "controls" VALUES('A.5.23','A.5.23','Segurança de informação no uso de serviços de nuvem','Processos para aquisição, uso, gestão e saída de serviços de nuvem devem ser estabelecidos de acordo com os requisitos de segurança de informação da organização.','Organizacional','ISO 27001:2022 A.5.23','partial','needs_improvement','DTI / ISO','','','2026-05-20 10:26:04','2026-05-20 10:26:04');
INSERT INTO "controls" VALUES('A.5.27','A.5.27','Aprendizagem a partir de incidentes','O conhecimento adquirido com incidentes de segurança de informação deve ser usado para fortalecer e melhorar os controlos.','Organizacional','ISO 27001:2022 A.5.27','partial','needs_improvement','ISO','','','2026-05-20 10:26:04','2026-05-20 10:26:04');
INSERT INTO "controls" VALUES('A.5.28','A.5.28','Recolha de evidências','A organização deve estabelecer e implementar procedimentos para identificação, recolha, aquisição e preservação de evidências relacionadas com eventos de segurança.','Organizacional','ISO 27001:2022 A.5.28','not_implemented','untested','ISO / Forense','','','2026-05-20 10:26:04','2026-05-20 10:26:04');
INSERT INTO "controls" VALUES('A.5.32','A.5.32','Direitos de propriedade intelectual','A organização deve implementar procedimentos apropriados para proteger direitos de propriedade intelectual.','Organizacional','ISO 27001:2022 A.5.32','partial','needs_improvement','Jurídico','','','2026-05-20 10:26:04','2026-05-20 10:26:04');
INSERT INTO "controls" VALUES('A.5.33','A.5.33','Proteção de registos','Os registos devem ser protegidos contra perda, destruição, falsificação, acesso não autorizado e divulgação não autorizada.','Organizacional','ISO 27001:2022 A.5.33','partial','needs_improvement','ISO','','','2026-05-20 10:26:04','2026-05-20 10:26:04');
INSERT INTO "controls" VALUES('A.5.35','A.5.35','Revisão independente da segurança de informação','A abordagem da organização para gerir a segurança de informação e a sua implementação deve ser revista independentemente em intervalos planeados ou quando ocorram alterações significativas.','Organizacional','ISO 27001:2022 A.5.35','not_implemented','untested','Auditoria Interna','','','2026-05-20 10:26:04','2026-05-20 10:26:04');
INSERT INTO "controls" VALUES('A.5.36','A.5.36','Conformidade com políticas, regras e padrões','A conformidade com a política de segurança de informação, políticas específicas, regras e normas da organização deve ser regularmente revista.','Organizacional','ISO 27001:2022 A.5.36','partial','needs_improvement','ISO / Auditoria','','','2026-05-20 10:26:04','2026-05-20 10:26:04');
INSERT INTO "controls" VALUES('A.6.1','A.6.1','Triagem','Verificações de antecedentes em todos os candidatos a pessoal devem ser realizadas antes de ingresso na organização e numa base contínua, considerando leis, regulamentos, ética, requisitos de negócio, classificação da informação e riscos percebidos.','Pessoas','ISO 27001:2022 A.6.1','partial','needs_improvement','RH','','','2026-05-20 10:26:04','2026-05-20 10:26:04');
INSERT INTO "controls" VALUES('A.6.2','A.6.2','Termos e condições de emprego','Os contratos de trabalho devem indicar as responsabilidades do pessoal e da organização em matéria de segurança de informação.','Pessoas','ISO 27001:2022 A.6.2','implemented','effective','RH / Jurídico','','','2026-05-20 10:26:04','2026-05-20 10:26:04');
INSERT INTO "controls" VALUES('A.6.4','A.6.4','Processo disciplinar','Um processo disciplinar formal deve ser estabelecido e comunicado para tomar ações contra pessoal e outras partes interessadas que tenham cometido uma violação da política de segurança.','Pessoas','ISO 27001:2022 A.6.4','partial','needs_improvement','RH / Jurídico','','','2026-05-20 10:26:04','2026-05-20 10:26:04');
INSERT INTO "controls" VALUES('A.6.5','A.6.5','Responsabilidades após cessação ou mudança de funções','Responsabilidades e deveres de segurança de informação que permanecem válidos após a cessação ou mudança de funções devem ser definidos, aplicados e comunicados.','Pessoas','ISO 27001:2022 A.6.5','implemented','effective','RH','','','2026-05-20 10:26:04','2026-05-20 10:26:04');
INSERT INTO "controls" VALUES('A.6.6','A.6.6','Acordos de confidencialidade ou não-divulgação (NDA)','Acordos de confidencialidade ou não-divulgação que reflitam as necessidades de proteção de informação da organização devem ser identificados, documentados, revistos regularmente e assinados pelo pessoal e partes interessadas.','Pessoas','ISO 27001:2022 A.6.6','implemented','effective','RH / Jurídico','','','2026-05-20 10:26:04','2026-05-20 10:26:04');
INSERT INTO "controls" VALUES('A.6.7','A.6.7','Trabalho remoto','Medidas de segurança devem ser implementadas quando o pessoal trabalha remotamente para proteger a informação acedida, processada ou armazenada fora das instalações da organização.','Pessoas','ISO 27001:2022 A.6.7','partial','needs_improvement','DTI - Segurança / RH','','','2026-05-20 10:26:04','2026-05-20 10:26:04');
INSERT INTO "controls" VALUES('A.7.3','A.7.3','Proteção de escritórios, salas e instalações','A segurança física para escritórios, salas e instalações deve ser projetada e implementada.','Físico','ISO 27001:2022 A.7.3','implemented','effective','Facilities','','','2026-05-20 10:26:04','2026-05-20 10:26:04');
INSERT INTO "controls" VALUES('A.7.4','A.7.4','Monitorização de segurança física','As instalações devem ser continuamente monitorizadas contra acessos físicos não autorizados.','Físico','ISO 27001:2022 A.7.4','implemented','effective','Segurança Física','','','2026-05-20 10:26:04','2026-05-20 10:26:04');
INSERT INTO "controls" VALUES('A.7.6','A.7.6','Trabalho em áreas seguras','Medidas de segurança para trabalho em áreas seguras devem ser projetadas e implementadas.','Físico','ISO 27001:2022 A.7.6','partial','needs_improvement','Facilities','','','2026-05-20 10:26:04','2026-05-20 10:26:04');
INSERT INTO "controls" VALUES('A.7.7','A.7.7','Secretária limpa e ecrã limpo','Regras de secretária limpa para papéis e suportes de armazenamento removíveis e regras de ecrã limpo para instalações de processamento de informação devem ser definidas e adequadamente aplicadas.','Físico','ISO 27001:2022 A.7.7','partial','needs_improvement','ISO','','','2026-05-20 10:26:04','2026-05-20 10:26:04');
INSERT INTO "controls" VALUES('A.7.8','A.7.8','Localização e proteção de equipamentos','Os equipamentos devem ser localizados de forma segura e protegidos.','Físico','ISO 27001:2022 A.7.8','implemented','effective','DTI - Infra','','','2026-05-20 10:26:04','2026-05-20 10:26:04');
INSERT INTO "controls" VALUES('A.7.9','A.7.9','Segurança de ativos fora das instalações','Ativos fora das instalações devem ser protegidos.','Físico','ISO 27001:2022 A.7.9','partial','needs_improvement','DTI','','','2026-05-20 10:26:04','2026-05-20 10:26:04');
INSERT INTO "controls" VALUES('A.7.10','A.7.10','Suportes de armazenamento','Os suportes de armazenamento devem ser geridos ao longo do seu ciclo de vida de aquisição, uso, transporte e eliminação, de acordo com o esquema de classificação e requisitos de manuseamento.','Físico','ISO 27001:2022 A.7.10','partial','needs_improvement','DTI','','','2026-05-20 10:26:04','2026-05-20 10:26:04');
INSERT INTO "controls" VALUES('A.7.11','A.7.11','Serviços de suporte (utilities)','Instalações de processamento de informação devem ser protegidas contra falhas de energia e outras disrupções causadas por falhas em serviços de suporte.','Físico','ISO 27001:2022 A.7.11','implemented','effective','Facilities','','','2026-05-20 10:26:04','2026-05-20 10:26:04');
INSERT INTO "controls" VALUES('A.7.12','A.7.12','Segurança de cablagem','Os cabos que transportam energia, dados ou informação de serviços de suporte devem ser protegidos contra interceção, interferência ou danos.','Físico','ISO 27001:2022 A.7.12','implemented','effective','DTI - Infra','','','2026-05-20 10:26:04','2026-05-20 10:26:04');
INSERT INTO "controls" VALUES('A.7.13','A.7.13','Manutenção de equipamentos','Os equipamentos devem ser corretamente mantidos para garantir disponibilidade, integridade e confidencialidade da informação.','Físico','ISO 27001:2022 A.7.13','implemented','effective','DTI - Infra','','','2026-05-20 10:26:04','2026-05-20 10:26:04');
INSERT INTO "controls" VALUES('A.7.14','A.7.14','Eliminação segura ou reutilização de equipamentos','Itens de equipamento que contenham suportes de armazenamento devem ser verificados para garantir que dados sensíveis e software licenciado foram removidos ou substituídos de forma segura antes da eliminação ou reutilização.','Físico','ISO 27001:2022 A.7.14','partial','needs_improvement','DTI - Infra','','','2026-05-20 10:26:04','2026-05-20 10:26:04');
INSERT INTO "controls" VALUES('A.8.1','A.8.1','Dispositivos de endpoint do utilizador','Informação armazenada, processada ou acessível através de dispositivos de endpoint do utilizador deve ser protegida.','Tecnológico','ISO 27001:2022 A.8.1','partial','needs_improvement','DTI - Segurança','','','2026-05-20 10:26:04','2026-05-20 10:26:04');
INSERT INTO "controls" VALUES('A.8.3','A.8.3','Restrição de acesso a informação','O acesso a informação e outros ativos associados deve ser restringido de acordo com a política de controlo de acessos estabelecida.','Tecnológico','ISO 27001:2022 A.8.3','implemented','effective','DTI - Segurança','','','2026-05-20 10:26:04','2026-05-20 10:26:04');
INSERT INTO "controls" VALUES('A.8.4','A.8.4','Acesso a código-fonte','O acesso de leitura e escrita ao código-fonte, ferramentas de desenvolvimento e bibliotecas de software deve ser apropriadamente gerido.','Tecnológico','ISO 27001:2022 A.8.4','partial','needs_improvement','DTI - Dev','','','2026-05-20 10:26:04','2026-05-20 10:26:04');
INSERT INTO "controls" VALUES('A.8.5','A.8.5','Autenticação segura','Tecnologias e procedimentos de autenticação segura devem ser implementados com base nas restrições de acesso a informação e na política específica de controlo de acessos.','Tecnológico','ISO 27001:2022 A.8.5 · NIS2 Art.21(2)(j)','partial','needs_improvement','DTI - Segurança','','','2026-05-20 10:26:04','2026-05-20 10:26:04');
INSERT INTO "controls" VALUES('A.8.6','A.8.6','Gestão de capacidade','O uso de recursos deve ser monitorizado e ajustado em linha com requisitos de capacidade atuais e expectáveis.','Tecnológico','ISO 27001:2022 A.8.6','partial','needs_improvement','DTI - Infra','','','2026-05-20 10:26:04','2026-05-20 10:26:04');
INSERT INTO "controls" VALUES('A.8.9','A.8.9','Gestão de configurações','Configurações, incluindo configurações de segurança, de hardware, software, serviços e redes, devem ser estabelecidas, documentadas, implementadas, monitorizadas e revistas.','Tecnológico','ISO 27001:2022 A.8.9','partial','needs_improvement','DTI - Infra','','','2026-05-20 10:26:04','2026-05-20 10:26:04');
INSERT INTO "controls" VALUES('A.8.11','A.8.11','Mascaramento de dados (data masking)','Mascaramento de dados deve ser usado de acordo com a política específica de controlo de acessos e outras políticas, e requisitos de negócio, tomando em consideração a legislação aplicável.','Tecnológico','ISO 27001:2022 A.8.11','not_implemented','untested','DTI - Dev','','','2026-05-20 10:26:04','2026-05-20 10:26:04');
INSERT INTO "controls" VALUES('A.8.12','A.8.12','Prevenção de fuga de dados (DLP)','Medidas de prevenção de fuga de dados devem ser aplicadas a sistemas, redes e outros dispositivos que processem, armazenem ou transmitam informação sensível.','Tecnológico','ISO 27001:2022 A.8.12','not_implemented','untested','DTI - Segurança','','','2026-05-20 10:26:04','2026-05-20 10:26:04');
INSERT INTO "controls" VALUES('A.8.17','A.8.17','Sincronização de relógios','Os relógios dos sistemas de processamento de informação usados pela organização devem ser sincronizados com fontes de tempo aprovadas.','Tecnológico','ISO 27001:2022 A.8.17','implemented','effective','DTI - Infra','','','2026-05-20 10:26:04','2026-05-20 10:26:04');
INSERT INTO "controls" VALUES('A.8.18','A.8.18','Uso de programas utilitários privilegiados','O uso de programas utilitários capazes de sobrepor controlos de sistema e aplicações deve ser restrito e rigorosamente controlado.','Tecnológico','ISO 27001:2022 A.8.18','partial','needs_improvement','DTI - Segurança','','','2026-05-20 10:26:04','2026-05-20 10:26:04');
INSERT INTO "controls" VALUES('A.8.19','A.8.19','Instalação de software em sistemas operacionais','Procedimentos e medidas devem ser implementados para gerir de forma segura a instalação de software em sistemas operacionais.','Tecnológico','ISO 27001:2022 A.8.19','partial','needs_improvement','DTI - Infra','','','2026-05-20 10:26:04','2026-05-20 10:26:04');
INSERT INTO "controls" VALUES('A.8.20','A.8.20','Segurança de redes','Redes e dispositivos de rede devem ser protegidos, geridos e controlados para proteger a informação em sistemas e aplicações.','Tecnológico','ISO 27001:2022 A.8.20','implemented','effective','DTI - Segurança','','','2026-05-20 10:26:04','2026-05-20 10:26:04');
INSERT INTO "controls" VALUES('A.8.21','A.8.21','Segurança de serviços de rede','Mecanismos de segurança, níveis de serviço e requisitos de serviço de serviços de rede devem ser identificados, implementados e monitorizados.','Tecnológico','ISO 27001:2022 A.8.21','partial','needs_improvement','DTI - Segurança','','','2026-05-20 10:26:04','2026-05-20 10:26:04');
INSERT INTO "controls" VALUES('A.8.22','A.8.22','Segregação de redes','Grupos de serviços de informação, utilizadores e sistemas de informação devem ser segregados nas redes da organização.','Tecnológico','ISO 27001:2022 A.8.22','partial','needs_improvement','DTI - Infra','','','2026-05-20 10:26:04','2026-05-20 10:26:04');
INSERT INTO "controls" VALUES('A.8.23','A.8.23','Filtragem web','O acesso a websites externos deve ser gerido para reduzir a exposição a conteúdo malicioso.','Tecnológico','ISO 27001:2022 A.8.23','implemented','effective','DTI - Segurança','','','2026-05-20 10:26:04','2026-05-20 10:26:04');
INSERT INTO "controls" VALUES('A.8.26','A.8.26','Requisitos de segurança de aplicações','Requisitos de segurança de informação devem ser identificados, especificados e aprovados aquando do desenvolvimento ou aquisição de aplicações.','Tecnológico','ISO 27001:2022 A.8.26','partial','needs_improvement','DTI - Dev','','','2026-05-20 10:26:04','2026-05-20 10:26:04');
INSERT INTO "controls" VALUES('A.8.27','A.8.27','Princípios de arquitetura e engenharia de sistemas seguros','Princípios para engenharia de sistemas seguros devem ser estabelecidos, documentados, mantidos e aplicados a qualquer atividade de desenvolvimento de sistemas.','Tecnológico','ISO 27001:2022 A.8.27','partial','needs_improvement','DTI - Dev','','','2026-05-20 10:26:04','2026-05-20 10:26:04');
INSERT INTO "controls" VALUES('A.8.29','A.8.29','Testes de segurança em desenvolvimento e aceitação','Processos de testes de segurança devem ser definidos e implementados no ciclo de vida de desenvolvimento.','Tecnológico','ISO 27001:2022 A.8.29','partial','needs_improvement','DTI - Dev / QA','','','2026-05-20 10:26:04','2026-05-20 10:26:04');
INSERT INTO "controls" VALUES('A.8.30','A.8.30','Desenvolvimento subcontratado (outsourcing)','A organização deve direcionar, monitorizar e rever as atividades relacionadas com desenvolvimento subcontratado.','Tecnológico','ISO 27001:2022 A.8.30','partial','needs_improvement','DTI - Dev / Compras','','','2026-05-20 10:26:04','2026-05-20 10:26:04');
INSERT INTO "controls" VALUES('A.8.31','A.8.31','Separação de ambientes de desenvolvimento, teste e produção','Ambientes de desenvolvimento, teste e produção devem ser separados e protegidos.','Tecnológico','ISO 27001:2022 A.8.31','implemented','effective','DTI - Dev','','','2026-05-20 10:26:04','2026-05-20 10:26:04');
INSERT INTO "controls" VALUES('A.8.32','A.8.32','Gestão de mudanças','Mudanças em instalações de processamento de informação e em sistemas de informação devem ser sujeitas a procedimentos de gestão de mudança.','Tecnológico','ISO 27001:2022 A.8.32','partial','needs_improvement','DTI','','','2026-05-20 10:26:04','2026-05-20 10:26:04');
INSERT INTO "controls" VALUES('A.8.33','A.8.33','Informação de teste','A informação de teste deve ser apropriadamente selecionada, protegida e gerida.','Tecnológico','ISO 27001:2022 A.8.33','partial','needs_improvement','DTI - Dev','','','2026-05-20 10:26:04','2026-05-20 10:26:04');
INSERT INTO "controls" VALUES('A.8.34','A.8.34','Proteção de sistemas durante testes de auditoria','Testes de auditoria e outras atividades de garantia que envolvam avaliação de sistemas operacionais devem ser planeados e acordados entre o auditor e a direção apropriada.','Tecnológico','ISO 27001:2022 A.8.34','partial','needs_improvement','Auditoria / DTI','','','2026-05-20 10:26:04','2026-05-20 10:26:04');
INSERT INTO "monthly_snapshots" VALUES('2026-05',36,1,25,10,0);
INSERT INTO "risks" VALUES('R001','Falhas em sistemas aplicacionais','Risco de falhas no desempenho ou disponibilidade das aplicações de negócio (Primavera, RecordM, Freshservice) que afetem a atividade normal da organização.','Tecnológico','high',4,3,12,'accepted','DTI','stable',NULL,'2026-05-18 10:04:54','2026-05-18 11:37:18',NULL,NULL,NULL,NULL);
INSERT INTO "risks" VALUES('R002','Falhas na infraestrutura IT','Risco de falhas na infraestrutura informática (servidores, redes, telecomunicações) que comprometam a atividade da organização. Agravado pelo período de migração de servidores em curso.','Tecnológico','medium',3,3,9,'in_treatment','DTI','stable',NULL,'2026-05-18 10:04:54','2026-05-18 11:37:18',NULL,NULL,NULL,NULL);
INSERT INTO "risks" VALUES('R003','Ciberataques e malware','Risco de ataques informáticos que comprometam sistemas e informação: bloqueio de sistemas por vírus (ransomware), ataques sofisticados prolongados, ataques de saturação dos sistemas, e emails fraudulentos (phishing).','Tecnológico','high',4,4,16,'in_treatment','ISO','up',NULL,'2026-05-18 10:04:54','2026-05-18 11:37:18',NULL,NULL,NULL,NULL);
INSERT INTO "risks" VALUES('R004','Acessos não autorizados ou excessivos','Risco de utilizadores internos ou externos terem acesso a sistemas ou dados além do necessário para a sua função.','Tecnológico','high',4,3,12,'in_treatment','ISO','stable',NULL,'2026-05-18 10:04:54','2026-05-18 11:37:18',NULL,NULL,NULL,NULL);
INSERT INTO "risks" VALUES('R005','Falha na recuperação de backups','Risco de perder informação por falhas no processo de cópias de segurança ou impossibilidade de recuperar os dados a tempo.','Tecnológico','medium',1,5,5,'in_treatment','DTI - Infra','down','V006','2026-05-18 10:04:54','2026-05-18 11:37:18',NULL,NULL,NULL,NULL);
INSERT INTO "risks" VALUES('R006','Comportamentos de risco por falta de consciencialização','Risco de incidentes de segurança causados por colaboradores sem formação adequada: caírem em emails fraudulentos, partilharem dados indevidamente, ou usarem ferramentas não aprovadas pela empresa.','Pessoas','high',4,3,12,'in_treatment','DTI / RH','stable',NULL,'2026-05-18 10:04:54','2026-05-18 11:37:18',NULL,NULL,NULL,NULL);
INSERT INTO "risks" VALUES('R007','Risco da cadeia de fornecimento (supply chain)','Risco de comprometimento da segurança através de fornecedores externos de informática ou cloud que tenham acessos elevados aos sistemas ou processem dados da organização.','Terceiros','high',3,4,12,'in_treatment','DTI / Compras','stable',NULL,'2026-05-18 10:04:54','2026-05-18 11:37:18',NULL,NULL,NULL,NULL);
INSERT INTO "risks" VALUES('R008','Incumprimento do RGPD','Risco de não cumprir as obrigações do Regulamento Geral de Proteção de Dados (RGPD) na recolha, tratamento, conservação e transferência de dados pessoais.','Legal e Regulamentar','high',3,4,12,'in_treatment','DPO','stable',NULL,'2026-05-18 10:04:54','2026-05-18 11:37:18',NULL,NULL,NULL,NULL);
INSERT INTO "risks" VALUES('R009','Incumprimento da diretiva NIS2','Risco de não conformidade com a diretiva europeia NIS2 enquanto entidade essencial ou importante. Coimas até 10M€ ou 2% do volume de negócios.','Legal e Regulamentar','high',3,4,12,'in_treatment','ISO / Compliance','stable',NULL,'2026-05-18 10:04:54','2026-05-18 11:37:18',NULL,NULL,NULL,NULL);
INSERT INTO "risks" VALUES('R010','Riscos de utilização de serviços cloud','Risco específico de utilizar serviços na cloud: configurações incorretas, acessos indevidos, dados armazenados fora da UE, e dificuldade em mudar de fornecedor.','Tecnológico','medium',3,3,9,'in_treatment','DTI - Cloud','stable','V001','2026-05-18 10:04:54','2026-05-18 11:37:18',NULL,NULL,NULL,NULL);
INSERT INTO "risks" VALUES('R011','Exploração de vulnerabilidades técnicas','Risco de atacantes explorarem fraquezas conhecidas em sistemas operativos, aplicações ou equipamentos por falta de aplicação de correções ou de reforço da configuração.','Tecnológico','high',4,4,16,'in_treatment','DTI - Infra','up',NULL,'2026-05-18 10:04:54','2026-05-18 11:37:18',NULL,NULL,NULL,NULL);
INSERT INTO "risks" VALUES('R012','Ausência de Plano de Continuidade de Negócio formal','Ausência de um plano formal de continuidade de negócio aprovado, capaz de manter as operações críticas em caso de incidente disruptivo (catástrofe, ataque informático grave, pandemia).','Organizacional','high',3,4,12,'in_treatment','DTI / Direção','down',NULL,'2026-05-18 10:04:54','2026-05-18 11:37:18',NULL,NULL,NULL,NULL);
INSERT INTO "risks" VALUES('R014','Pegada ambiental da infraestrutura IT','Risco do consumo energético dos centros de dados próprios e dos serviços na cloud face às metas de redução de emissões de carbono.','ESG','medium',3,2,6,'open','DTI / Sustentabilidade','stable',NULL,'2026-05-18 10:04:54','2026-05-18 11:37:18',NULL,NULL,NULL,NULL);
INSERT INTO "risks" VALUES('R015','Falha física no Datacenter (incêndio/inundação)','Risco de dano físico no centro de dados por incêndio, inundação ou falha do sistema de extinção durante o período de remodelação.','Físico','medium',1,5,5,'in_treatment','DTI - Infra','stable',NULL,'2026-05-18 10:40:20','2026-05-18 11:37:18',NULL,NULL,NULL,NULL);
INSERT INTO "risks" VALUES('R016','Controlo de acessos físicos inadequado','Risco de acessos físicos não autorizados às instalações por ausência ou falha do sistema de videovigilância e controlo de acessos.','Físico','medium',2,3,6,'in_treatment','DTI - Infra','stable',NULL,'2026-05-18 10:40:20','2026-05-18 11:37:18',NULL,NULL,NULL,NULL);
INSERT INTO "risks" VALUES('R017','Falta de visibilidade de segurança (sem SIEM)','Ausência de uma ferramenta de monitorização de segurança operacional impede a deteção atempada de incidentes e o cruzamento de eventos suspeitos.','Tecnológico','critical',5,4,20,'in_treatment','DTI - Segurança','stable',NULL,'2026-05-18 10:40:20','2026-05-18 11:37:18',NULL,NULL,NULL,NULL);
INSERT INTO "risks" VALUES('R018','Processos manuais de onboarding/offboarding','Processos de entrada e saída de colaboradores executados manualmente aumentam o risco de acessos que ficam ativos depois da saída e erros operacionais.','Processos','high',4,3,12,'in_treatment','DTI / RH','down',NULL,'2026-05-18 10:40:20','2026-05-18 11:37:18',NULL,NULL,NULL,NULL);
INSERT INTO "risks" VALUES('R019','Dependência do ERP Primavera (sistema legacy)','Dependência crítica do sistema central de gestão (Primavera ERP) sem plano claro de evolução, com risco de o fornecedor descontinuar o suporte e dificuldades em integrar com sistemas mais modernos.','Estratégico','high',3,4,12,'in_treatment','DTI / DPGT','stable','V007','2026-05-18 10:40:20','2026-05-18 11:37:18',NULL,NULL,NULL,NULL);
INSERT INTO "risks" VALUES('R020','Ponto único de falha nas telecomunicações (MEO)','Dependência de um único operador (MEO) para comunicações fixas e rede de dados cria risco de indisponibilidade total em caso de falha do operador.','Tecnológico','medium',3,3,9,'in_treatment','DTI - Infra','stable',NULL,'2026-05-18 10:40:20','2026-05-18 11:37:18',NULL,NULL,NULL,NULL);
INSERT INTO "risks" VALUES('R021','Fraude por IA generativa (BEC/deepfake)','Risco de ataques de manipulação potenciados por inteligência artificial: emails fraudulentos altamente personalizados, imitação por vídeo e voz de executivos, e criação automática de pretextos credíveis para conseguir transferências bancárias ou palavras-passe.','Tecnológico','high',3,4,12,'open','ISO','up',NULL,'2026-05-18 11:25:40','2026-05-18 11:37:18',NULL,NULL,NULL,NULL);
INSERT INTO "risks" VALUES('R022','Shadow AI (utilização não supervisionada de IA)','Risco de colaboradores utilizarem ferramentas de inteligência artificial não aprovadas para processar dados internos, confidenciais ou pessoais, sem controlos de segurança, criando exposição de dados e incumprimento regulatório.','Tecnológico','high',5,3,15,'open','DTI / ISO','up',NULL,'2026-05-18 11:25:40','2026-05-18 11:37:18',NULL,NULL,NULL,NULL);
INSERT INTO "risks" VALUES('R023','Obsolescência tecnológica acelerada','Risco do portfólio de informática ficar desatualizado face ao ritmo de mudança tecnológica (inteligência artificial, cloud, automação), comprometendo a competitividade operacional e criando dívida técnica com custos crescentes de manutenção.','Estratégico','high',4,3,12,'open','DTI / Direção','stable',NULL,'2026-05-18 11:25:40','2026-05-18 11:37:18',NULL,NULL,NULL,NULL);
INSERT INTO "risks" VALUES('R024','Indisponibilidade de fornecedor crítico de cloud/SaaS','Risco de indisponibilidade prolongada de plataformas críticas na cloud (Microsoft 365, Azure, OKTA) por incidente no fornecedor, afetando a produtividade total da organização sem alternativa imediata.','Terceiros','medium',2,4,8,'open','DTI - Cloud','stable','V001','2026-05-18 11:25:40','2026-05-18 11:37:18',NULL,NULL,NULL,NULL);
INSERT INTO "risks" VALUES('R025','Falta de classificação dos dados','Não está definido o que é informação confidencial, interna ou pública. Sem essa definição, não é possível aplicar controlos diferenciados de proteção.','Processos','high',5,3,15,'open','ISO / DPO','stable',NULL,'2026-05-18 11:37:18','2026-05-18 11:37:18',NULL,NULL,NULL,NULL);
INSERT INTO "risks" VALUES('R026','Contas de administrador sem ferramenta de controlo dedicada','Contas com privilégios elevados (administradores de sistemas, bases de dados, aplicações) são geridas sem uma ferramenta especializada que controle quem acede, quando, e o que faz.','Tecnológico','high',4,4,16,'open','DTI - Segurança','stable',NULL,'2026-05-18 11:37:18','2026-05-18 11:37:18',NULL,NULL,NULL,NULL);
INSERT INTO "risks" VALUES('R027','Erros humanos e falhas de processo no dia-a-dia','Risco de incidentes causados por erros operacionais involuntários, falhas de seguimento de procedimentos, ou ausência de procedimentos documentados.','Processos','high',5,2,10,'open','DTI','stable',NULL,'2026-05-18 11:37:18','2026-05-18 11:37:18',NULL,NULL,NULL,NULL);
INSERT INTO "risks" VALUES('R028','Dados pessoais guardados mais tempo do que é permitido por lei','Risco de manter dados pessoais para além dos prazos legais aplicáveis por ausência de uma política de retenção e processo de eliminação automatizada.','Legal e Regulamentar','high',4,3,12,'open','DPO','stable',NULL,'2026-05-18 11:37:18','2026-05-18 11:37:18',NULL,NULL,NULL,NULL);
INSERT INTO "risks" VALUES('R029','Registos de atividade insuficientes','Enquanto a ferramenta de monitorização de segurança não estiver em produção, os registos das atividades dos utilizadores e sistemas não são guardados nem analisados de forma centralizada.','Tecnológico','high',4,3,12,'open','DTI - Segurança','stable',NULL,'2026-05-18 11:37:18','2026-05-18 11:37:18',NULL,NULL,NULL,NULL);
INSERT INTO "risks" VALUES('R030','Gestão das chaves de cifragem não documentada','Risco de perda ou comprometimento de chaves criptográficas usadas para proteger dados, por ausência de processo formal de criação, armazenamento, rotação e eliminação.','Tecnológico','medium',2,4,8,'open','DTI - Segurança','stable',NULL,'2026-05-18 11:37:18','2026-05-18 11:37:18',NULL,NULL,NULL,NULL);
INSERT INTO "risks" VALUES('R031','Falta de processo formal para desenvolver software interno em segurança','Se forem desenvolvidas aplicações internamente (scripts, automações, integrações), não existe um processo documentado que assegure que a segurança é considerada desde o desenho.','Processos','high',4,3,12,'open','DTI','stable',NULL,'2026-05-18 11:37:18','2026-05-18 11:37:18',NULL,NULL,NULL,NULL);
INSERT INTO "risks" VALUES('R032','Registo de tratamentos de dados pessoais em falta','Não existe um registo atualizado de todas as atividades em que a organização trata dados pessoais. Este registo é obrigatório pelo Artigo 30 do RGPD.','Legal e Regulamentar','high',4,3,12,'open','DPO','stable',NULL,'2026-05-18 11:37:18','2026-05-18 11:37:18',NULL,NULL,NULL,NULL);
INSERT INTO "risks" VALUES('R033','Transferências de dados pessoais para fornecedores nos EUA sem salvaguardas formais','Dados pessoais são processados por fornecedores nos EUA (Microsoft, OpenAI, OKTA, Freshservice) sem que estejam formalizadas cláusulas contratuais padrão de proteção de dados e análises de impacto da transferência.','Legal e Regulamentar','high',4,4,16,'open','DPO','stable','V001','2026-05-18 11:37:18','2026-05-18 11:37:18',NULL,NULL,NULL,NULL);
INSERT INTO "risks" VALUES('R034','Avaliações de impacto sobre proteção de dados em falta','Atividades de tratamento de elevado risco (videovigilância Genetec, monitorização SIEM, piloto ChatGPT, Talentia) deveriam ter avaliações formais de impacto sobre proteção de dados, conforme o Artigo 35 do RGPD.','Legal e Regulamentar','high',4,3,12,'open','DPO','stable','V005','2026-05-18 11:37:18','2026-05-18 11:37:18',NULL,NULL,NULL,NULL);
INSERT INTO "risks" VALUES('R035','Risco de não cumprir os prazos de aviso ao regulador em caso de incidente','O RGPD obriga a comunicar incidentes de segurança à CNPD em 72 horas. A NIS2 exige aviso prévio em 24 horas. Sem procedimento documentado, contactos pré-definidos e modelos, estes prazos são difíceis de cumprir.','Legal e Regulamentar','high',3,4,12,'open','ISO / DPO','up',NULL,'2026-05-18 11:37:18','2026-05-18 11:37:18',NULL,NULL,NULL,NULL);
INSERT INTO "risks" VALUES('R036','Ausência de plano formal de resposta a incidentes','Não existe um documento aprovado que defina quem decide, quem comunica, e que passos seguir em caso de incidente de segurança. Em situação real, isto traduz-se em demoras, decisões inconsistentes e maior impacto.','Processos','high',4,4,16,'open','ISO','stable',NULL,'2026-05-18 11:37:18','2026-05-18 11:37:18',NULL,NULL,NULL,NULL);
INSERT INTO "risks" VALUES('R037','Ausência de contrato com empresa especializada em investigação forense','Em caso de incidente grave que exija análise forense (recolha de evidências, investigação técnica detalhada), não existe contrato prévio com empresa especializada. Contratar reactivamente atrasa a resposta e aumenta custos.','Terceiros','medium',3,3,9,'open','ISO','stable',NULL,'2026-05-18 11:37:18','2026-05-18 11:37:18',NULL,NULL,NULL,NULL);
