-- ============================================================
-- RiskSafe - Snapshot completo da BD (BASELINE PARTILHADO)
-- Gerado: 2026-05-27
-- Fonte de verdade versionavel dos dados. Sem PII / sem segredos.
--
-- Restaurar:  python restore_db.py
-- Atualizar:  python dump_db.py
-- ============================================================

BEGIN TRANSACTION;
CREATE TABLE action_plans (
	id VARCHAR NOT NULL, 
	risk_id VARCHAR NOT NULL, 
	title VARCHAR NOT NULL, 
	owner VARCHAR, 
	due_date VARCHAR, 
	status VARCHAR, 
	created_at DATETIME DEFAULT CURRENT_TIMESTAMP, 
	updated_at DATETIME DEFAULT CURRENT_TIMESTAMP, 
	PRIMARY KEY (id), 
	FOREIGN KEY(risk_id) REFERENCES risks (id)
);
CREATE TABLE assets (
	id VARCHAR NOT NULL, 
	name VARCHAR NOT NULL, 
	type VARCHAR, 
	owner VARCHAR, 
	criticality VARCHAR, 
	status VARCHAR, 
	vendor VARCHAR, 
	contract_id VARCHAR, 
	risk_ids VARCHAR, 
	description VARCHAR, 
	created_at DATETIME DEFAULT CURRENT_TIMESTAMP, 
	updated_at DATETIME DEFAULT CURRENT_TIMESTAMP, 
	PRIMARY KEY (id)
);
CREATE TABLE contracts (
	id VARCHAR NOT NULL, 
	vendor_id VARCHAR, 
	title VARCHAR, 
	start_date VARCHAR, 
	end_date VARCHAR, 
	value FLOAT, 
	sla_compliance FLOAT, 
	status VARCHAR, 
	auto_renew BOOLEAN, 
	PRIMARY KEY (id), 
	FOREIGN KEY(vendor_id) REFERENCES vendors (id)
);
CREATE TABLE control_evidence (
	id VARCHAR NOT NULL, 
	control_id VARCHAR NOT NULL, 
	original_name VARCHAR NOT NULL, 
	stored_name VARCHAR NOT NULL, 
	file_size INTEGER, 
	mime_type VARCHAR, 
	uploaded_at VARCHAR NOT NULL, 
	uploaded_by VARCHAR, 
	notes VARCHAR, 
	PRIMARY KEY (id)
);
CREATE TABLE controls (
	id VARCHAR NOT NULL, 
	code VARCHAR, 
	name VARCHAR NOT NULL, 
	description TEXT, 
	category VARCHAR, 
	framework_refs TEXT, 
	status VARCHAR, 
	effectiveness VARCHAR, 
	owner VARCHAR, 
	risk_ids TEXT, 
	notes TEXT, 
	created_at DATETIME DEFAULT CURRENT_TIMESTAMP, 
	updated_at DATETIME DEFAULT CURRENT_TIMESTAMP, 
	PRIMARY KEY (id)
);
CREATE TABLE monthly_snapshots (
	month VARCHAR NOT NULL, 
	total INTEGER, 
	critical INTEGER, 
	high INTEGER, 
	medium INTEGER, 
	low INTEGER, 
	PRIMARY KEY (month)
);
CREATE TABLE questionnaires (
	id VARCHAR NOT NULL, 
	vendor_id VARCHAR, 
	title VARCHAR, 
	status VARCHAR, 
	sent_at VARCHAR, 
	due_date VARCHAR, 
	completed_at VARCHAR, 
	score INTEGER, 
	PRIMARY KEY (id), 
	FOREIGN KEY(vendor_id) REFERENCES vendors (id)
);
CREATE TABLE risks (
	id VARCHAR NOT NULL, 
	name VARCHAR NOT NULL, 
	description TEXT, 
	category VARCHAR, 
	level VARCHAR, 
	probability INTEGER, 
	impact INTEGER, 
	score INTEGER, 
	status VARCHAR, 
	owner VARCHAR, 
	trend VARCHAR, 
	vendor_id VARCHAR, 
	created_at DATETIME DEFAULT CURRENT_TIMESTAMP, 
	updated_at DATETIME DEFAULT CURRENT_TIMESTAMP, residual_probability INTEGER, residual_impact INTEGER, residual_score INTEGER, residual_level VARCHAR, 
	PRIMARY KEY (id), 
	FOREIGN KEY(vendor_id) REFERENCES vendors (id)
);
CREATE TABLE settings (
	id VARCHAR NOT NULL, 
	org_name VARCHAR, 
	org_sector VARCHAR, 
	org_nif VARCHAR, 
	org_logo_url VARCHAR, 
	org_frameworks TEXT, 
	org_nis2_classification VARCHAR, 
	matrix_size INTEGER, 
	prob_labels TEXT, 
	impact_labels TEXT, 
	threshold_low_max INTEGER, 
	threshold_medium_max INTEGER, 
	threshold_high_max INTEGER, 
	risk_appetite INTEGER, 
	risk_tolerance INTEGER, 
	risk_categories TEXT, 
	asset_types TEXT, 
	user_name VARCHAR, 
	user_email VARCHAR, 
	user_role VARCHAR, 
	PRIMARY KEY (id)
);
CREATE TABLE vendors (
	id VARCHAR NOT NULL, 
	name VARCHAR NOT NULL, 
	category VARCHAR, 
	criticality VARCHAR, 
	contact_name VARCHAR, 
	contact_email VARCHAR, 
	country VARCHAR, 
	status VARCHAR, 
	risk_score INTEGER, 
	contract_end VARCHAR, 
	created_at DATETIME DEFAULT CURRENT_TIMESTAMP, 
	PRIMARY KEY (id)
);
CREATE INDEX ix_vendors_id ON vendors (id);
CREATE INDEX ix_risks_id ON risks (id);
CREATE INDEX ix_questionnaires_id ON questionnaires (id);
CREATE INDEX ix_contracts_id ON contracts (id);
CREATE INDEX ix_action_plans_id ON action_plans (id);
CREATE INDEX ix_assets_id ON assets (id);
CREATE INDEX ix_controls_id ON controls (id);
CREATE INDEX ix_control_evidence_control_id ON control_evidence (control_id);
COMMIT;
